      specs: [{ param: '可用类型' }, { param: '承载能力' }, { param: '输送速度' }, { param: '皮带/链条宽度' }, { param: '运行温度' }, { param: '自动识别' }, { param: '弯道和分流' }, { param: 'ASRS集成' }],
